import React from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Shield, Activity, Users, Globe } from 'lucide-react';

const Landing = () => {
    const navigate = useNavigate();

    const handleRoleSelect = (role) => {
        navigate(`/login?role=${role}`);
    };

    return (
        <div className="min-h-screen bg-[#050510] relative flex items-center justify-center p-6 overflow-hidden font-['Outfit']">
            {/* Cinematic Background Elements */}
            <div className="absolute inset-0 overflow-hidden">
                <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/20 rounded-full blur-[120px]" />
                <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/20 rounded-full blur-[120px]" />
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-[0.03]" />
            </div>

            <div className="relative z-10 max-w-7xl w-full">
                <div className="text-center mb-16">
                    <motion.div 
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="inline-flex items-center gap-3 bg-white/5 backdrop-blur-xl px-6 py-2 rounded-full border border-white/10 mb-8"
                    >
                        <Activity className="text-cyan-400 w-4 h-4" />
                        <span className="text-[10px] font-black uppercase tracking-[0.3em] text-cyan-400">Industry-Leading 2026 Engine</span>
                    </motion.div>

                    <motion.h1 
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: 0.1 }}
                        className="text-6xl lg:text-8xl font-black tracking-tighter text-white mb-6 uppercase"
                    >
                        VITA-CORE <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-cyan-400">2.0</span>
                    </motion.h1>

                    <motion.p 
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ delay: 0.2 }}
                        className="text-lg text-white/40 max-w-2xl mx-auto leading-relaxed"
                    >
                        The world’s first agentic, HL7 FHIR-compliant disease prediction ecosystem. 
                        Augmenting human clinical decisions with real-time explainable AI reasoning.
                    </motion.p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 px-4 lg:px-32">
                    <motion.div 
                        whileHover={{ scale: 1.02, translateY: -5 }}
                        className="group relative cursor-pointer"
                        onClick={() => handleRoleSelect('patient')}
                    >
                        <div className="absolute inset-0 bg-blue-600/20 blur-2xl opacity-0 group-hover:opacity-100 transition-opacity" />
                        <div className="relative bg-white/5 backdrop-blur-2xl border border-white/10 p-10 rounded-[40px] h-full flex flex-col items-center text-center transition-all group-hover:border-cyan-500/50">
                            <div className="w-20 h-20 bg-blue-500/10 rounded-3xl flex items-center justify-center mb-8 border border-white/10 group-hover:border-blue-500/30">
                                <Users className="text-blue-400 w-10 h-10" />
                            </div>
                            <h3 className="text-2xl font-bold mb-4">Patient Experience</h3>
                            <p className="text-sm text-white/40 mb-8 leading-relaxed">Interactive 3D digital twin, clinical SOAP notes, and real-time health path tracking.</p>
                            <button className="mt-auto px-8 py-4 bg-white/10 hover:bg-white/20 rounded-2xl w-full font-black text-xs uppercase tracking-widest transition-all">Launch Patient Portal</button>
                        </div>
                    </motion.div>

                    <motion.div 
                        whileHover={{ scale: 1.02, translateY: -5 }}
                        className="group relative cursor-pointer"
                        onClick={() => handleRoleSelect('doctor')}
                    >
                        <div className="absolute inset-0 bg-purple-600/20 blur-2xl opacity-0 group-hover:opacity-100 transition-opacity" />
                        <div className="relative bg-white/5 backdrop-blur-2xl border border-white/10 p-10 rounded-[40px] h-full flex flex-col items-center text-center transition-all group-hover:border-purple-500/50">
                            <div className="w-20 h-20 bg-purple-500/10 rounded-3xl flex items-center justify-center mb-8 border border-white/10 group-hover:border-purple-500/30">
                                <Shield className="text-purple-400 w-10 h-10" />
                            </div>
                            <h3 className="text-2xl font-bold mb-4">Clinician Dashboard</h3>
                            <p className="text-sm text-white/40 mb-8 leading-relaxed">Cohort analytics, FHIR records, predictive risk alerts, and GNN-based correlations.</p>
                            <button className="mt-auto px-8 py-4 bg-white/10 hover:bg-white/20 rounded-2xl w-full font-black text-xs uppercase tracking-widest transition-all">Launch Doctor Portal</button>
                        </div>
                    </motion.div>
                </div>

                <div className="mt-24 flex justify-center gap-12 text-white/20">
                    <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.2em]">
                        <Globe className="w-3 h-3" /> HL7 FHIR GLOBAL STANDARDS
                    </div>
                    <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.2em]">
                        <Shield className="w-3 h-3" /> HIPAA COMPLIANT AES-256
                    </div>
                    <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.2em]">
                        <Shield className="w-3 h-3" /> AGENTIC REASONING ENABLED
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Landing;
